package com.example.search.service;

import com.example.search.index.Indices;
import com.example.search.model.Product;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.List;
import java.util.UUID;

@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductIndexService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public String index(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        if (product.getCreatedAt() == null) product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());

        IndexRequest req = new IndexRequest(Indices.PRODUCTS)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), XContentType.JSON)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);

        client.index(req, RequestOptions.DEFAULT);
        return product.getId();
    }

    public BulkResponse bulkIndex(List<Product> products) throws IOException {
        BulkRequest bulk = new BulkRequest();
        Instant now = Instant.now();

        for (Product p : products) {
            if (p.getId() == null || p.getId().isBlank()) {
                p.setId(UUID.randomUUID().toString());
            }
            if (p.getCreatedAt() == null) p.setCreatedAt(now);
            p.setUpdatedAt(now);

            bulk.add(new IndexRequest(Indices.PRODUCTS)
                    .id(p.getId())
                    .source(objectMapper.writeValueAsString(p), XContentType.JSON));
        }

        bulk.setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL);
        return client.bulk(bulk, RequestOptions.DEFAULT);
    }

    public void deleteById(String id) throws IOException {
        client.delete(new DeleteRequest(Indices.PRODUCTS, id).setRefreshPolicy(WriteRequest.RefreshPolicy.WAIT_UNTIL), RequestOptions.DEFAULT);
    }
}

package com.example.search.service;

import com.example.search.dto.SearchRequestDto;
import com.example.search.dto.SearchResponseDto;
import com.example.search.index.Indices;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryEvent;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.support.WriteRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.unit.Fuzziness;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.index.query.RangeQueryBuilder;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.range.Range;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.aggregations.metrics.Min;
import org.elasticsearch.search.aggregations.metrics.Max;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public SearchResponseDto search(SearchRequestDto req, String userId, String sessionId) throws IOException {
        int page = req.getPage() == null ? 0 : Math.max(0, req.getPage());
        int size = req.getSize() == null ? 20 : Math.min(200, Math.max(1, req.getSize()));
        int from = page * size;

        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        String q = req.getQ();
        if (q == null || q.isBlank()) {
            bool.must(QueryBuilders.matchAllQuery());
        } else {
            bool.must(QueryBuilders.multiMatchQuery(q, "title^3", "description", "brand", "categories", "tags")
                    .type(org.elasticsearch.index.query.MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .operator(Operator.AND)
                    .fuzziness(Fuzziness.AUTO));
        }

        if (req.getCategories() != null && !req.getCategories().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("categories", req.getCategories()));
        }

        if (req.getBrands() != null && !req.getBrands().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("brand", req.getBrands()));
        }

        if (req.getInStock() != null) {
            bool.filter(QueryBuilders.termQuery("inStock", req.getInStock()));
        }

        if (req.getPriceMin() != null || req.getPriceMax() != null) {
            RangeQueryBuilder range = QueryBuilders.rangeQuery("price");
            if (req.getPriceMin() != null) range.gte(req.getPriceMin());
            if (req.getPriceMax() != null) range.lte(req.getPriceMax());
            bool.filter(range);
        }

        if (req.getAttributes() != null && !req.getAttributes().isEmpty()) {
            for (Map.Entry<String, Object> e : req.getAttributes().entrySet()) {
                String field = "attributes." + e.getKey();
                Object val = e.getValue();
                if (val instanceof Collection) {
                    bool.filter(QueryBuilders.termsQuery(field, (Collection<?>) val));
                } else {
                    bool.filter(QueryBuilders.termQuery(field, val));
                }
            }
        }

        SearchSourceBuilder source = new SearchSourceBuilder()
                .query(bool)
                .from(from)
                .size(size)
                .trackTotalHits(true);

        applySort(req.getSort(), source);

        source.aggregation(AggregationBuilders.terms("facet_brand").field("brand").size(50));
        source.aggregation(AggregationBuilders.terms("facet_category").field("categories").size(50));
        source.aggregation(AggregationBuilders.terms("facet_inStock").field("inStock").size(2));
        source.aggregation(AggregationBuilders.min("price_min").field("price"));
        source.aggregation(AggregationBuilders.max("price_max").field("price"));
        source.aggregation(AggregationBuilders.range("price_ranges").field("price")
                .addUnboundedTo(25)
                .addRange(25, 50)
                .addRange(50, 100)
                .addRange(100, 250)
                .addRange(250, 500)
                .addUnboundedFrom(500));

        SearchRequest searchRequest = new SearchRequest(Indices.PRODUCTS).source(source);
        long start = System.currentTimeMillis();
        SearchResponse resp = client.search(searchRequest, RequestOptions.DEFAULT);
        long tookMs = System.currentTimeMillis() - start;

        List<Product> items = new ArrayList<>();
        for (SearchHit hit : resp.getHits().getHits()) {
            Map<String, Object> m = hit.getSourceAsMap();
            Product p = objectMapper.convertValue(m, Product.class);
            if (p.getId() == null) p.setId(hit.getId());
            items.add(p);
        }

        long total = resp.getHits().getTotalHits() == null ? items.size() : resp.getHits().getTotalHits().value;

        Map<String, Object> facets = new LinkedHashMap<>();
        facets.put("brand", termsToFacet(resp, "facet_brand"));
        facets.put("category", termsToFacet(resp, "facet_category"));
        facets.put("inStock", termsToFacet(resp, "facet_inStock"));

        Min minAgg = resp.getAggregations().get("price_min");
        Max maxAgg = resp.getAggregations().get("price_max");
        Map<String, Object> priceStats = new LinkedHashMap<>();
        priceStats.put("min", minAgg == null || Double.isInfinite(minAgg.getValue()) ? null : minAgg.getValue());
        priceStats.put("max", maxAgg == null || Double.isInfinite(maxAgg.getValue()) ? null : maxAgg.getValue());
        facets.put("priceStats", priceStats);

        Range ranges = resp.getAggregations().get("price_ranges");
        if (ranges != null) {
            List<Map<String, Object>> pr = new ArrayList<>();
            for (Range.Bucket b : ranges.getBuckets()) {
                Map<String, Object> r = new LinkedHashMap<>();
                r.put("key", b.getKeyAsString());
                r.put("from", b.getFrom());
                r.put("to", b.getTo());
                r.put("count", b.getDocCount());
                pr.add(r);
            }
            facets.put("priceRanges", pr);
        }

        indexSearchQueryEvent(req, userId, sessionId, total, tookMs);

        return new SearchResponseDto(total, page, size, items, facets);
    }

    private void applySort(String sort, SearchSourceBuilder source) {
        if (sort == null || sort.isBlank() || "relevance".equalsIgnoreCase(sort)) return;

        switch (sort.toLowerCase(Locale.ROOT)) {
            case "price_asc":
                source.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC).unmappedType("double"));
                break;
            case "price_desc":
                source.sort(SortBuilders.fieldSort("price").order(SortOrder.DESC).unmappedType("double"));
                break;
            case "newest":
                source.sort(SortBuilders.fieldSort("createdAt").order(SortOrder.DESC).unmappedType("date"));
                break;
            case "rating_desc":
                source.sort(SortBuilders.fieldSort("rating").order(SortOrder.DESC).unmappedType("double"));
                break;
            default:
                break;
        }
    }

    private List<Map<String, Object>> termsToFacet(SearchResponse resp, String aggName) {
        Terms t = resp.getAggregations().get(aggName);
        if (t == null) return Collections.emptyList();
        List<Map<String, Object>> out = new ArrayList<>();
        for (Terms.Bucket b : t.getBuckets()) {
            Map<String, Object> o = new LinkedHashMap<>();
            o.put("value", b.getKeyAsString());
            o.put("count", b.getDocCount());
            out.add(o);
        }
        return out;
    }

    private void indexSearchQueryEvent(SearchRequestDto req, String userId, String sessionId, long resultCount, long tookMs) {
        try {
            SearchQueryEvent ev = new SearchQueryEvent();
            ev.setId(UUID.randomUUID().toString());
            ev.setQuery(req.getQ());

            Map<String, Object> filters = new LinkedHashMap<>();
            if (req.getCategories() != null) filters.put("categories", req.getCategories());
            if (req.getBrands() != null) filters.put("brands", req.getBrands());
            if (req.getPriceMin() != null) filters.put("priceMin", req.getPriceMin());
            if (req.getPriceMax() != null) filters.put("priceMax", req.getPriceMax());
            if (req.getInStock() != null) filters.put("inStock", req.getInStock());
            if (req.getAttributes() != null) filters.put("attributes", req.getAttributes());
            ev.setFilters(filters.isEmpty() ? null : filters);

            ev.setSort(req.getSort());
            ev.setPage(req.getPage());
            ev.setSize(req.getSize());
            ev.setUserId(userId);
            ev.setSessionId(sessionId);
            ev.setTimestamp(Instant.now());
            ev.setResultCount(resultCount);
            ev.setTookMs(tookMs);

            IndexRequest idx = new IndexRequest(Indices.SEARCH_QUERIES)
                    .id(ev.getId())
                    .source(objectMapper.writeValueAsString(ev), XContentType.JSON)
                    .setRefreshPolicy(WriteRequest.RefreshPolicy.NONE);

            client.index(idx, RequestOptions.DEFAULT);
        } catch (Exception ignored) {
        }
    }
}

